sol! {

    // Contract from: status-network-monorepo/status-network-contracts/src/rln/RLN.sol
    // Bytecode compile (in status-network-monorepo):
    // Note: you need to install openzeppelin libs
    //       use: make status-network-contracts-setup for that or follow the instructions manually
    // cd status-network-contracts
    // docker run -v ./:/sources ethereum/solc:0.8.26 --bin --via-ir --optimize --optimize-runs 1 --overwrite  @openzeppelin/contracts=/sources/lib/openzeppelin-contracts/contracts @openzeppelin/contracts-upgradeable=/sources/lib/openzeppelin-contracts-upgradeable/contracts /sources/src/rln/RLN.sol

    #[sol(rpc, bytecode="")]
    contract RLN {

        error RLN__MemberNotFound();
        error RLN__IdCommitmentAlreadyRegistered();
        error RLN__Unauthorized();
        error RLN__InvalidRevealStartTime();
        error RLN__InvalidCommitment(address expected);
        error RLN__RevealWindowNotStarted();
        error RLN__InvalidSlashRevealWindowTime(uint256 windowTime);

        event MemberRegistered(uint256 identityCommitment, uint256 index);
        event MemberSlashed(uint256 index, address slasher);

        struct User {
            address userAddress;
            uint256 index;
        }

        function register(uint256 identityCommitment, address user) external onlyRole(REGISTER_ROLE);
        // mapping(uint256 commitment => User user) public members;
        function members(uint256 commitment) public view returns (User memory);

        function slashCommit(address account, bytes32 hash) external onlyRole(SLASHER_ROLE);

        // mapping(address account => uint256 lastRevealStartTime) public lastRevealStartTime;
        function lastRevealStartTime(address account) public view returns (uint256);

        // mapping(address account => mapping(bytes32 hash => uint256 revealStartTime)) public slashCommitments;
        function slashCommitments(address account, bytes32 hash) public view returns (uint256);

        function slashReveal(
            address account,
            bytes32 privateKey,
            address rewardRecipient
        ) external onlyRole(SLASHER_ROLE);

        function initialize(
            address _owner,
            address _slasher,
            address _register,
            address _token,
            address _poseidonHasher
        ) public initializer;
    }
}

impl<P: Provider> RLN::RLNInstance<P> {
    pub(crate) async fn slash(
        &self,
        account_to_slash: Address,
        identity_secret_hash: IdSecret,
        account_for_reward: Address,
    ) -> Result<(), SlashError> {
        let slash_commit_hash = {
            let to_hash = (
                U256::from_limbs(identity_secret_hash.into_bigint().0).to_be_bytes::<32>(),
                account_for_reward,
            );
            let slash_commit_hash_ = to_hash.abi_encode_packed();
            // println!("slash_commit_hash_: {:?}", slash_commit_hash_);
            keccak256(slash_commit_hash_.as_slice())
        };

        let _ = self
            .slashCommit(account_to_slash, slash_commit_hash.0.into())
            .send()
            .await?
            .watch()
            .await?;

        // Now call slashReveal
        let pkey_fb32 = U256::from_limbs(identity_secret_hash.into_bigint().0)
            .to_be_bytes::<32>()
            .into();

        let slash_reveal_call_result = self
            .slashReveal(account_to_slash, pkey_fb32, account_for_reward)
            .call()
            .await;
        if let Err(e) = slash_reveal_call_result {
            // Error can come from either RLN SC or Karma SC
            let rln_errors = e.as_decoded_interface_error::<RLN::RLNErrors>();
            if let Some(rln_errors) = rln_errors {
                return Err(SlashError::RlnSc(rln_errors.into()));
            };
            let karma_sc_errors = e.as_decoded_interface_error::<KarmaSC::KarmaSCErrors>();
            if let Some(karma_sc_errors) = karma_sc_errors {
                return Err(SlashError::KarmaSc(karma_sc_errors.into()));
            };

            error!("Error in slash reveal: {:#?}", e);
        }

        let _slash_reveal_tx = self
            .slashReveal(account_to_slash, pkey_fb32, account_for_reward)
            .send()
            .await?
            .watch()
            .await?;

        Ok(())
    }
}

#[derive(Debug, Display)]
pub enum RlnScError {
    MemberNotFound,
    IdCommitmentAlreadyRegistered,
    Unauthorized,
    InvalidRevealStartTime,
    InvalidCommitment,
    RevealWindowNotStarted,
    InvalidSlashRevealWindowTime,
}

impl From<RLNErrors> for RlnScError {
    fn from(e: RLNErrors) -> Self {
        match e {
            RLNErrors::RLN__MemberNotFound(_) => RlnScError::MemberNotFound,
            RLNErrors::RLN__IdCommitmentAlreadyRegistered(_) => {
                RlnScError::IdCommitmentAlreadyRegistered
            }
            RLNErrors::RLN__Unauthorized(_) => RlnScError::Unauthorized,
            RLNErrors::RLN__InvalidRevealStartTime(_) => RlnScError::InvalidRevealStartTime,
            RLNErrors::RLN__InvalidCommitment(_) => RlnScError::InvalidCommitment,
            RLNErrors::RLN__RevealWindowNotStarted(_) => RlnScError::RevealWindowNotStarted,
            RLNErrors::RLN__InvalidSlashRevealWindowTime(_) => {
                RlnScError::InvalidSlashRevealWindowTime
            }
        }
    }
}

impl std::error::Error for RlnScError {}

#[derive(Debug, Display)]
pub enum KarmaScError {
    InvalidAddress,
    TransfersNotAllowed,
    DistributorAlreadyAdded,
    UnknownDistributor,
    Unauthorized,
    InvalidSlashPercentage,
    InvalidSlashRewardPercentage,
    CannotSlashZeroBalance,
    InsufficientTransferBalance,
    // Debug,
}

impl From<KarmaSCErrors> for KarmaScError {
    fn from(e: KarmaSCErrors) -> Self {
        match e {
            KarmaSCErrors::Karma__InvalidAddress(_) => KarmaScError::InvalidAddress,
            KarmaSCErrors::Karma__TransfersNotAllowed(_) => KarmaScError::TransfersNotAllowed,
            KarmaSCErrors::Karma__DistributorAlreadyAdded(_) => {
                KarmaScError::DistributorAlreadyAdded
            }
            KarmaSCErrors::Karma__UnknownDistributor(_) => KarmaScError::UnknownDistributor,
            KarmaSCErrors::Karma__Unauthorized(_) => KarmaScError::Unauthorized,
            KarmaSCErrors::Karma__InvalidSlashPercentage(_) => KarmaScError::InvalidSlashPercentage,
            KarmaSCErrors::Karma__InvalidSlashRewardPercentage(_) => {
                KarmaScError::InvalidSlashRewardPercentage
            }
            KarmaSCErrors::Karma__CannotSlashZeroBalance(_) => KarmaScError::CannotSlashZeroBalance,
            KarmaSCErrors::Karma__InsufficientTransferBalance(_) => {
                KarmaScError::InsufficientTransferBalance
            }
        }
    }
}

impl std::error::Error for KarmaScError {}

#[derive(thiserror::Error, Debug)]
pub enum SlashError {
    #[error(transparent)]
    Contract(#[from] alloy::contract::Error),
    #[error(transparent)]
    PendingTransaction(#[from] alloy::providers::PendingTransactionError),
    #[error(transparent)]
    RlnSc(#[from] RlnScError),
    #[error(transparent)]
    KarmaSc(#[from] KarmaScError),
}

sol! {
    // src: status-network-contracts/src/Karma.sol
    // Compile bytecode (in status-network-contracts)
    // docker run -v ./:/sources ethereum/solc:0.8.26 --bin --via-ir --optimize --optimize-runs 1 --overwrite  @openzeppelin/contracts=/sources/lib/openzeppelin-contracts/contracts @openzeppelin/contracts-upgradeable=/sources/lib/openzeppelin-contracts-upgradeable/contracts /sources/src/Karma.sol

    #[sol(rpc, bytecode="")]
    // #[sol(rpc, bytecode="")]
    // #[sol(rpc, bytecode="")]
    contract KarmaSC {

        /// @notice Emitted when the address is invalid
        error Karma__InvalidAddress();
        /// @notice Emitted because transfers are not allowed
        error Karma__TransfersNotAllowed();
        /// @notice Emitted when distributor is already added
        error Karma__DistributorAlreadyAdded();
        /// @notice Emitted when distributor is not found
        error Karma__UnknownDistributor();
        /// @notice Emitted sender does not have the required role
        error Karma__Unauthorized();
        /// @notice Emitted when slash percentage to set is invalid
        error Karma__InvalidSlashPercentage();
        /// @notice Emitted when slash reward percentage is invalid
        error Karma__InvalidSlashRewardPercentage();
        /// @notice Emitted when balance to slash is invalid
        error Karma__CannotSlashZeroBalance();
        /// @notice Emitted when there are insufficient funds to transfer
        error Karma__InsufficientTransferBalance();

        // error Karma__Debug(uint256 toslash, uint256 reward);

        // From: https://github.com/OpenZeppelin/openzeppelin-contracts/blob/master/contracts/token/ERC20/IERC20.sol#L16
        event Transfer(address indexed from, address indexed to, uint256 value);
        /// @notice Emitted when an account is slashed
        event AccountSlashed(
            address indexed account, uint256 amount, address indexed rewardRecipient, uint256 rewardAmount
        );

        function balanceOf(address account) public view override returns (uint256);

        function initialize(address _owner) public initializer;

        function totalSupply() public view virtual override returns (uint256);
        function name() public view virtual override returns (string memory);

        // function _totalSupply() internal view returns (uint256);
        function mint(address account, uint256 amount) public virtual onlyAdminOrOperator;
        function addRewardDistributor(address distributor) public virtual onlyRole(DEFAULT_ADMIN_ROLE);
        function setAllowedToTransfer(address account, bool allowed) public onlyRole(DEFAULT_ADMIN_ROLE);
        function setReward(address rewardsDistributor,uint256 amount,uint256 duration);

        // for unit tests
        bytes32 public constant SLASHER_ROLE = 0x12b42e8a160f6064dc959c6f251e3af0750ad213dbecf573b4710d67d6c28e39;
        // Function defined in AccessControlUpgradeable.sol
        function grantRole(bytes32 role, address account) public virtual override onlyRole(getRoleAdmin(role));
    }
}

